function pageFor(path) {
  let normalized = path;
  if (normalized !== '/' && !normalized.endsWith('/')) normalized += '/';
  const meta = ROUTES[normalized];
  if (meta === undefined) return null;
  if (!meta) return BASE_HTML;
  const [hashroute,title,desc] = meta;
  let html = BASE_HTML
    .replace('<title>Superbuy Spreadsheet 2026: Finds, QC & Shipping Guide | SuperbuyVIP</title>', `<title>${title}</title>`)
    .replace('<meta name="description" content="SuperbuyVIP offers an updated Superbuy spreadsheet, curated product finds, QC photo guidance, W2C resources, shipping guides, coupons and transparent service-fee explanations." />', `<meta name="description" content="${desc.replaceAll('&','&amp;').replaceAll('\"','&quot;')}" />`)
    .replace('<link rel="canonical" href="https://superbuyvip.shop/" />', `<link rel="canonical" href="https://superbuyvip.shop${normalized}" />`)
    .replace('</head>', `<script>if(!location.hash) location.hash=${JSON.stringify(hashroute)};<\/script>\n</head>`);
  return html;
}
